#include <bits/stdc++.h>
using namespace std;

int dis[205][205], b[100005];

int main()
{
	int n, m, ans = 0;
	cin >> n >> m;
	memset(dis, 0x3f, sizeof dis);
	for(int i = 1; i <= m; i++)
		cin >> b[i];
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= n; j++)
			cin >> dis[i][j];
	for(int i = 1; i <= n; i++)
		dis[i][i] = 0;
	for(int k = 1; k <= n; k++)
		for(int i = 1; i <= n; i++)
			for(int j = 1; j <= n; j++)
				dis[i][j] = min(dis[i][j], dis[i][k] + dis[k][j]);
	b[0] = 1;
	for(int i = 1; i <= m; i++)
		ans += dis[b[i - 1]][b[i]];
	cout << ans;
	return 0;
}
